{
  "command": "sqlite3 '/workspace/DataAgentBench/query_googlelocal/query_dataset/review_query.db' \"SELECT time, rating FROM review LIMIT 5;\"",
  "description": "Sample review rows"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_googlelocal/query_dataset/review_query.db' \"SELECT DISTINCT substr(time,1,4) as prefix, COUNT(*) FROM review GROUP BY prefix ORDER BY COUNT(*) DESC LIMIT 20;\"",
  "description": "Check time format prefixes"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_googlelocal/query_dataset/review_query.db' \"SELECT time FROM review WHERE substr(time,1,4) = '07 J' LIMIT 5;\"",
  "description": "Check 07 J format"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_googlelocal/query_dataset/review_query.db' \"SELECT DISTINCT time FROM review WHERE time NOT LIKE '____-%' AND time NOT LIKE '% __, 20__ at%' AND time NOT LIKE '__ ___ 20__,%' LIMIT 20;\"",
  "description": "Find other time formats"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_googlelocal/query_dataset/review_query.db' \"SELECT gmap_id, COUNT(*) as cnt FROM review WHERE rating >= 4.5 AND time LIKE '%2019%' GROUP BY gmap_id ORDER BY cnt DESC LIMIT 10;\"",
  "description": "Top gmap_ids with high rating reviews in 2019"
}

{
  "command": "psql -h 127.0.0.1 -U user -d googlelocal_db -c \"SELECT gmap_id, name FROM business_description WHERE gmap_id IN ('gmap_35','gmap_53','gmap_20');\"",
  "description": "Get business names for top gmap_ids"
}
